1	import { quote, claim, policyCap } from "./claim-office.js";
2	
3	type Customer = { yearsWithMHPCO: number; previousContract: boolean };
4	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
5	type QuoteStep = { op: "quote"; items: Item[] };
6	type ClaimStep = { op: "claim"; policy: number; incident: { damages: { itemType: string; amount: number }[] } };
7	type Step = QuoteStep | ClaimStep;
8	type Scenario = { customer: { yearsWithMHPCO: number; previousContract?: boolean }; steps: Step[] };
9	type QuoteResult = { premium: number };
10	type ClaimResult = { payout: number; remainingCap: number };
11	type StepResult = QuoteResult | ClaimResult;
12	
13	function readStdin(): Promise<string> {
14	  return new Promise((resolve) => {
15	    let buffer = "";
16	    process.stdin.on("data", (chunk) => {
17	      buffer += chunk;
18	    });
19	    process.stdin.on("end", () => resolve(buffer));
20	  });
21	}
22	
23	function normalizeCustomer(customer: Scenario["customer"]): Customer {
24	  return {
25	    yearsWithMHPCO: customer.yearsWithMHPCO,
26	    previousContract: customer.previousContract ?? false,
27	  };
28	}
29	
30	function runScenario(scenario: Scenario): { results: StepResult[] } {
31	  const customer = normalizeCustomer(scenario.customer);
32	  const results: StepResult[] = [];
33	  const steps = scenario.steps;
34	  for (const step of steps) {
35	    if (step.op === "quote") {
36	      results.push({ premium: quote({ customer, items: step.items }) });
37	    } else if (step.op === "claim") {
38	      const policyItems = (steps[step.policy] as QuoteStep).items;
39	      const policy = { remainingCap: policyCap(policyItems), items: policyItems };
40	      results.push(claim(policy, step.incident));
41	    }
42	  }
43	  return { results };
44	}
45	
46	async function main(): Promise<void> {
47	  const input = await readStdin();
48	  const scenario: Scenario = JSON.parse(input);
49	  const output = runScenario(scenario);
50	  process.stdout.write(JSON.stringify(output));
51	}
52	
53	main();
